import React from "react";
import styled, { keyframes } from 'styled-components';
import { slideInLeft, fadeIn } from 'react-animations';
const Intro = () => {
    const profilePhoto = require('../resources/profile.png');
    const SlideIn = styled.div`animation: 2s ${keyframes`${slideInLeft}`} 1 `;
    const FadeIn = styled.div`animation: 2s ${keyframes`${fadeIn}`} 1;transition-delay: 10s;`;
    return (

        <div className="ui center aligned segment">
            <SlideIn>
            <div className="ui centered small circular image" style={{borderRadius:"50%",padding: "0em", maxHeight:"50rem",maxWidth:"50rem",zIndex:"5"}}>
                <img src={profilePhoto}/>
            </div>
            </SlideIn>
            <div className="content">
                <h1 className="ui header">Hi there!</h1>
                <h1 className="ui header">My name is Daniel</h1>
                <h3>I am a software engineer currently residing in Auckland,NZ</h3>
                <h3>I am passionate about
                    <span className="container">
                        <span className="text text-a">a</span>
                        <span className="text text-u">u</span>
                        <span className="text text-d">d</span>
                        <span className="text text-i">i</span>
                        <span className="text text-o">o</span>
                    </span>
                    and
                    <div className="graphics-container">
                    {/*<ul className="graphics">*/}
                    {/*    <li className="c-graphics__layer c-graphics__layer--white">GRAPHICS</li>*/}
                    {/*    <li className="c-graphics__layer c-graphics__layer--orange">GRAPHICS</li>*/}
                    {/*    <li className="c-graphics__layer c-graphics__layer--red">GRAPHICS</li>*/}
                    {/*    <li className="c-graphics__layer c-graphics__layer--violet">GRAPHICS</li>*/}
                    {/*    <li className="c-graphics__layer c-graphics__layer--blue">GRAPHICS</li>*/}
                    {/*    <li className="c-graphics__layer c-graphics__layer--green">GRAPHICS</li>*/}
                    {/*    <li className="c-graphics__layer c-graphics__layer--yellow">GRAPHICS</li>*/}
                    {/*</ul>*/}
                        <ul className="c-rainbow">
                            <li className="c-rainbow__layer c-rainbow__layer--white">RAINBOW</li>
                            <li className="c-rainbow__layer c-rainbow__layer--orange">RAINBOW</li>
                            <li className="c-rainbow__layer c-rainbow__layer--red">RAINBOW</li>
                            <li className="c-rainbow__layer c-rainbow__layer--violet">RAINBOW</li>
                            <li className="c-rainbow__layer c-rainbow__layer--blue">RAINBOW</li>
                            <li className="c-rainbow__layer c-rainbow__layer--green">RAINBOW</li>
                            <li className="c-rainbow__layer c-rainbow__layer--yellow">RAINBOW</li>
                        </ul>
                    </div>
                    <span> rendering</span></h3>
            </div>

            {/*<FadeIn><div className="ui centered" style={{backgroundColor:"orange",top:"5px",width:"100em",height:"30em",position:"absolute",zIndex:"3"}}></div></FadeIn>*/}
        </div>

    )
};
export default Intro;
